import { useCue } from './useCue';

export type CueCalloutState = {
  dismiss: () => void;
  isActive: boolean;
};

const inactiveCalloutState: CueCalloutState = {
  dismiss: () => undefined,
  isActive: false,
};

/**
 * Single-step callout hook. Returns an inactive no-op state for tour cues —
 * use `useCue` / `useCueAnchor` for multi-step tours (same pattern as
 * `useCueAnchor` returning inactive state for single-step cues).
 */
export const useCueCallout = (): CueCalloutState => {
  const cue = useCue();

  if (cue.mode !== 'single') {
    return inactiveCalloutState;
  }

  return {
    dismiss: cue.dismiss,
    isActive: cue.eligible,
  };
};
